class Solution:
    def longestSubsequence(self, s: str, k: int) -> int:
        dp = [[0] * (len(s) + 1) for _ in range(32)]
        for i in range(len(s) - 1, -1, -1):
            for j in range(31):
                dp[j][i] = dp[j][i + 1]
                if s[i] == '1':
                    if j < 31:
                        dp[j + 1][i] = max(dp[j + 1][i], dp[j][i + 1] + 1)
                else:
                    dp[j][i] = max(dp[j][i], dp[j][i + 1] + 1)
        for i in range(31):
            if int('1' * i + '0' * (32 - i), 2) <= k:
                return dp[i][0]
        return 0
